import{_ as a,a as t,b as o,c as r}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as n,o as i,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Magnet Transfer","description":"","frontmatter":{},"headers":[],"relativePath":"en/Other/magnet-transfer.md","filePath":"en/Other/magnet-transfer.md","lastUpdated":1781962217000}'),d={name:"en/Other/magnet-transfer.md"};function h(p,e,c,f,u,m){return i(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="magnet-transfer" tabindex="-1">Magnet Transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet Transfer&quot;">​</a></h1><p>Magnet transfer downloads files from a magnet link and uploads them automatically to the cloud storage channel you choose.</p><p>It is useful for transferring anime episodes, videos, archives, and similar files. Paste a magnet link, and ImgBed creates a background download task. After the download finishes, the file is uploaded to ImgBed and the final link appears in the upload list.</p><p><img src="'+a+'" alt="Magnet transfer" loading="lazy"></p><h2 id="where-to-use-it" tabindex="-1">Where To Use It <a class="header-anchor" href="#where-to-use-it" aria-label="Permalink to &quot;Where To Use It&quot;">​</a></h2><p>The magnet transfer entry is in the homepage upload area.</p><p>Paste the magnet link into the input box, choose <code>Transfer</code>, then upload.</p><p><img src="'+t+'" alt="Upload anime" loading="lazy"></p><h2 id="before-first-use" tabindex="-1">Before First Use <a class="header-anchor" href="#before-first-use" aria-label="Permalink to &quot;Before First Use&quot;">​</a></h2><p>Configure magnet transfer in the admin panel first.</p><p>You usually need:</p><ol><li>A GitHub account for running the download task.</li><li>A cloud upload channel, such as Google Drive or OneDrive.</li><li>The target upload directory.</li><li>A task timeout.</li></ol><p>After the settings are ready, return to the homepage and paste a magnet link to start transfer.</p><h2 id="uploading-a-magnet-link" tabindex="-1">Uploading a Magnet Link <a class="header-anchor" href="#uploading-a-magnet-link" aria-label="Permalink to &quot;Uploading a Magnet Link&quot;">​</a></h2><ol><li>Paste the magnet link into the homepage upload box.</li><li>Make sure the mode is set to <code>Transfer</code>.</li><li>Click upload.</li><li>Wait for ImgBed to create the magnet task.</li><li>After the task starts, use the <code>Magnet Tasks</code> floating panel in the bottom-right corner to check progress.</li></ol><p>Download and upload can take time. Speed depends on the magnet resource, the GitHub runtime environment, and the selected cloud storage channel.</p><p><img src="'+o+'" alt="Magnet downloading" loading="lazy"></p><h2 id="after-completion" tabindex="-1">After Completion <a class="header-anchor" href="#after-completion" aria-label="Permalink to &quot;After Completion&quot;">​</a></h2><p>After the task completes, the upload list shows the file name and link.</p><p>Videos show video preview, images show image preview, and other files show a regular file icon.</p><p><img src="'+r+'" alt="Downloaded video" loading="lazy"></p><p>You can copy:</p><table tabindex="0"><thead><tr><th>Link Type</th><th>Use Case</th></tr></thead><tbody><tr><td>Original link</td><td>Direct file access</td></tr><tr><td>Markdown</td><td>Markdown posts or notes</td></tr><tr><td>HTML</td><td>Web page code</td></tr><tr><td>BBCode</td><td>Forums that support BBCode</td></tr></tbody></table><h2 id="magnet-task-panel" tabindex="-1">Magnet Task Panel <a class="header-anchor" href="#magnet-task-panel" aria-label="Permalink to &quot;Magnet Task Panel&quot;">​</a></h2><p>The bottom-right magnet task panel shows task count, task name, progress, and final status.</p><p>Common states:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td>Waiting</td><td>The task is created and waiting to run.</td></tr><tr><td>Downloading</td><td>The magnet resource is being downloaded.</td></tr><tr><td>Uploading</td><td>The file has downloaded and is being uploaded to cloud storage.</td></tr><tr><td>Completed</td><td>Upload succeeded and the link can be copied.</td></tr><tr><td>Failed</td><td>The task did not finish successfully. Check the message and try again.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>If a magnet link contains multiple files, ImgBed prioritizes the main completed file for display.</li><li>Large files take longer. Wait for the task to finish before refreshing the page.</li><li>If the magnet resource has no available peers, it may be very slow or fail.</li><li>If the cloud account is out of quota, authorization has expired, or the upload directory is wrong, the task may fail.</li><li>Video preview may take a few seconds after upload completes.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="nothing-starts-after-i-paste-a-magnet-link" tabindex="-1">Nothing Starts After I Paste a Magnet Link <a class="header-anchor" href="#nothing-starts-after-i-paste-a-magnet-link" aria-label="Permalink to &quot;Nothing Starts After I Paste a Magnet Link&quot;">​</a></h3><p>Confirm magnet transfer is enabled in the admin panel and that a usable GitHub account and cloud channel have been selected.</p><h3 id="download-is-always-slow" tabindex="-1">Download Is Always Slow <a class="header-anchor" href="#download-is-always-slow" aria-label="Permalink to &quot;Download Is Always Slow&quot;">​</a></h3><p>Magnet speed depends on the resource itself. If there are no available peers, the download may be very slow or impossible.</p><h3 id="no-preview-appears-after-upload" tabindex="-1">No Preview Appears After Upload <a class="header-anchor" href="#no-preview-appears-after-upload" aria-label="Permalink to &quot;No Preview Appears After Upload&quot;">​</a></h3><p>First confirm the file link opens. Video files may need a short time to load in the browser, or you can open the link directly.</p><h3 id="what-should-i-check-if-a-task-fails" tabindex="-1">What Should I Check If a Task Fails? <a class="header-anchor" href="#what-should-i-check-if-a-task-fails" aria-label="Permalink to &quot;What Should I Check If a Task Fails?&quot;">​</a></h3><p>Check whether the magnet link is valid, whether the cloud channel works, and whether the upload directory is correct. Then submit the task again.</p>',38)])])}const w=n(d,[["render",h]]);export{b as __pageData,w as default};
